beforeJsCode:
var data = arguments[1] || {};
var idticket = data.id || data["id"];

if(!idticket){
    alert("No se encontró el ID del ticket");
    return false;
}

if(window.parent){
    window.parent.postMessage({
        source: "selector_ticket",
        idticket: idticket
    }, "*");
}

return false;
